  1→import { Hono } from "hono";
  2→import type { AppEnv } from "../types";
  3→
  4→const cardsRoute = new Hono<AppEnv>();
  5→
  6→function safeJsonParse<T>(value: string | null | undefined, fallback: T): T {
  7→  if (!value || typeof value !== "string") return fallback;
  8→  try {
  9→    return JSON.parse(value) as T;
 10→  } catch {
 11→    return fallback;
 12→  }
 13→}
 14→
 15→function parseIntegerParam(value: string): number | null {
 16→  if (!value) return null;
 17→  const parsed = Number.parseInt(value, 10);
 18→  return Number.isNaN(parsed) ? null : parsed;
 19→}
 20→
 21→/** Reconstruct the original damage value (number | string) from damage_raw */
 22→function reconstructDamage(raw: string): string | number | undefined {
 23→  if (!raw) return undefined;
 24→  const num = parseInt(raw, 10);
 25→  if (!isNaN(num) && String(num) === raw) return num;
 26→  return raw;
 27→}
 28→
 29→/** Group an array of rows by a string key */
 30→function groupBy<T extends Record<string, unknown>>(rows: T[], key: keyof T): Map<string, T[]> {
 31→  const map = new Map<string, T[]>();
 32→  for (const row of rows) {
 33→    const k = String(row[key]);
 34→    const arr = map.get(k);
 35→    if (arr) arr.push(row);
 36→    else map.set(k, [row]);
 37→  }
 38→  return map;
 39→}
 40→
 41→/** Build attack objects matching original API shape */
 42→function assembleAttacks(rows: any[]): any[] {
 43→  return rows.map((r) => {
 44→    const attack: Record<string, unknown> = {
 45→      cost: safeJsonParse(r.cost, []),
 46→      name: r.name,
 47→    };
 48→    const damage = reconstructDamage(r.damage_raw);
 49→    if (damage !== undefined) attack.damage = damage;
 50→    if (r.effect != null) attack.effect = r.effect;
 51→    return attack;
 52→  });
 53→}
 54→
 55→/** Attach related data (attacks, abilities, types, modifiers) to a card row */
 56→function assembleCard(
 57→  card: Record<string, unknown>,
 58→  attacks: any[],
 59→  abilities: any[],
 60→  modifiers: any[],
 61→  types: any[],
 62→): Record<string, unknown> {
 63→  return {
 64→    ...card,
 65→    types: types.map((t: any) => t.type),
 66→    attacks: assembleAttacks(attacks),
 67→    abilities: abilities.map((a: any) => ({ type: a.type, name: a.name, effect: a.effect })),
 68→    weaknesses: modifiers
 69→      .filter((m: any) => m.kind === "weakness")
 70→      .map((m: any) => ({ type: m.type, value: m.value })),
 71→    resistances: modifiers
 72→      .filter((m: any) => m.kind === "resistance")
 73→      .map((m: any) => ({ type: m.type, value: m.value })),
 74→  };
 75→}
 76→
 77→// ---------------------------------------------------------------------------
 78→// GET /filters
 79→// ---------------------------------------------------------------------------
 80→
 81→cardsRoute.get("/filters", async (c) => {
 82→  const db = c.env.DB;
 83→
 84→  const [
 85→    categories,
 86→    rarities,
 87→    stages,
 88→    trainerTypes,
 89→    energyTypes,
 90→    types,
 91→    weaknesses,
 92→    resistances,
 93→    retreats,
 94→    hpRange,
 95→    regulationMarks,
 96→  ] = await Promise.all([
 97→    db.prepare("SELECT DISTINCT category FROM cards WHERE category IS NOT NULL ORDER BY category").all(),
 98→    db.prepare("SELECT DISTINCT rarity FROM cards WHERE rarity IS NOT NULL ORDER BY rarity").all(),
 99→    db.prepare("SELECT DISTINCT stage FROM cards WHERE stage IS NOT NULL ORDER BY stage").all(),
100→    db.prepare("SELECT DISTINCT trainer_type FROM cards WHERE trainer_type IS NOT NULL ORDER BY trainer_type").all(),
101→    db.prepare("SELECT DISTINCT energy_type FROM cards WHERE energy_type IS NOT NULL ORDER BY energy_type").all(),
102→    db.prepare("SELECT DISTINCT type FROM card_types ORDER BY type").all(),
103→    db.prepare("SELECT DISTINCT type FROM card_type_modifiers WHERE kind = 'weakness' ORDER BY type").all(),
104→    db.prepare("SELECT DISTINCT type FROM card_type_modifiers WHERE kind = 'resistance' ORDER BY type").all(),
105→    db.prepare("SELECT DISTINCT retreat FROM cards WHERE retreat IS NOT NULL ORDER BY retreat").all(),
106→    db.prepare("SELECT MIN(CAST(hp AS INTEGER)) as min, MAX(CAST(hp AS INTEGER)) as max FROM cards WHERE hp IS NOT NULL").first<{ min: number; max: number }>(),
107→    db.prepare("SELECT DISTINCT regulation_mark FROM cards WHERE regulation_mark IS NOT NULL ORDER BY regulation_mark").all(),
108→  ]);
109→
110→  c.header("Cache-Control", "public, max-age=300, s-maxage=86400, stale-while-revalidate=86400");
111→
112→  return c.json({
113→    categories: categories.results.map((r) => r.category),
114→    rarities: rarities.results.map((r) => r.rarity),
115→    stages: stages.results.map((r) => r.stage),
116→    trainer_types: trainerTypes.results.map((r) => r.trainer_type),
117→    energy_types: energyTypes.results.map((r) => r.energy_type),
118→    types: types.results.map((r) => r.type),
119→    weaknesses: weaknesses.results.map((r) => r.type),
120→    resistances: resistances.results.map((r) => r.type),
121→    retreats: retreats.results.map((r) => r.retreat),
122→    hp: { min: hpRange?.min ?? 0, max: hpRange?.max ?? 0 },
123→    regulation_marks: regulationMarks.results.map((r) => r.regulation_mark),
124→  });
125→});
126→
