131→cardsRoute.get("/", async (c) => {
132→  const db = c.env.DB;
133→
134→  const q = c.req.query("q")?.trim() || "";
135→  const category = c.req.query("category")?.trim() || "";
136→  const set = c.req.query("set")?.trim() || "";
137→  const rarity = c.req.query("rarity")?.trim() || "";
138→  const stage = c.req.query("stage")?.trim() || "";
139→  const trainerType = c.req.query("trainer_type")?.trim() || "";
140→  const energyType = c.req.query("energy_type")?.trim() || "";
141→  const retreat = c.req.query("retreat")?.trim() || "";
142→  const hpMin = c.req.query("hp_min")?.trim() || "";
143→  const hpMax = c.req.query("hp_max")?.trim() || "";
144→  const legalStandard = c.req.query("legal_standard")?.trim() || "";
145→  const legalExpanded = c.req.query("legal_expanded")?.trim() || "";
146→  const typesParam = c.req.query("types")?.trim() || "";
147→  const weaknessParam = c.req.query("weakness")?.trim() || "";
148→  const resistanceParam = c.req.query("resistance")?.trim() || "";
149→  const limit = Math.min(Math.max(parseInt(c.req.query("limit") || "40", 10) || 40, 1), 100);
150→  const offset = Math.max(parseInt(c.req.query("offset") || "0", 10) || 0, 0);
151→
152→  const conditions: string[] = [];
153→  const params: (string | number)[] = [];
154→
155→  if (q) {
156→    conditions.push("c.name LIKE ?");
157→    params.push(`%${q}%`);
158→  }
159→  if (category) {
160→    conditions.push("c.category = ?");
161→    params.push(category);
162→  }
163→  if (set) {
164→    conditions.push("c.set_id = ?");
165→    params.push(set);
166→  }
167→  if (rarity) {
168→    conditions.push("c.rarity = ?");
169→    params.push(rarity);
170→  }
171→  if (stage) {
172→    conditions.push("c.stage = ?");
173→    params.push(stage);
174→  }
175→  if (trainerType) {
176→    conditions.push("c.trainer_type = ?");
177→    params.push(trainerType);
178→  }
179→  if (energyType) {
180→    conditions.push("c.energy_type = ?");
181→    params.push(energyType);
182→  }
183→  if (retreat) {
184→    conditions.push("c.retreat = ?");
185→    params.push(retreat);
186→  }
187→  const hpMinValue = parseIntegerParam(hpMin);
188→  if (hpMinValue !== null) {
189→    conditions.push("CAST(c.hp AS INTEGER) >= ?");
190→    params.push(hpMinValue);
191→  }
192→  const hpMaxValue = parseIntegerParam(hpMax);
193→  if (hpMaxValue !== null) {
194→    conditions.push("CAST(c.hp AS INTEGER) <= ?");
195→    params.push(hpMaxValue);
196→  }
197→  if (legalStandard) {
198→    conditions.push("c.legal_standard = 1");
199→  }
200→  if (legalExpanded) {
201→    conditions.push("c.legal_expanded = 1");
202→  }
203→  if (typesParam) {
204→    const values = typesParam.split(",").map((v) => v.trim()).filter(Boolean);
205→    if (values.length > 0) {
206→      const orClauses = values.map(() => "EXISTS (SELECT 1 FROM card_types ct WHERE ct.card_id = c.id AND ct.type = ?)");
207→      conditions.push(`(${orClauses.join(" OR ")})`);
208→      params.push(...values);
209→    }
210→  }
211→  if (weaknessParam) {
212→    const values = weaknessParam.split(",").map((v) => v.trim()).filter(Boolean);
213→    if (values.length > 0) {
214→      const orClauses = values.map(() => "EXISTS (SELECT 1 FROM card_type_modifiers m WHERE m.card_id = c.id AND m.kind = 'weakness' AND m.type = ?)");
215→      conditions.push(`(${orClauses.join(" OR ")})`);
216→      params.push(...values);
217→    }
218→  }
219→  if (resistanceParam) {
220→    const values = resistanceParam.split(",").map((v) => v.trim()).filter(Boolean);
221→    if (values.length > 0) {
222→      const orClauses = values.map(() => "EXISTS (SELECT 1 FROM card_type_modifiers m WHERE m.card_id = c.id AND m.kind = 'resistance' AND m.type = ?)");
223→      conditions.push(`(${orClauses.join(" OR ")})`);
224→      params.push(...values);
225→    }
226→  }
227→
228→  const filters = conditions.length > 0 ? ` AND ${conditions.join(" AND ")}` : "";
229→
230→  const countResult = await db.prepare(
231→    `SELECT COUNT(*) as count FROM cards c WHERE c.image IS NOT NULL AND c.image != ''${filters}`
232→  )
233→    .bind(...params)
234→    .first<{ count: number }>();
235→
236→  const total = countResult?.count ?? 0;
237→
238→  const rows = await db.prepare(
239→    `SELECT c.id, c.local_id, c.name, c.image, c.category, c.rarity, c.hp,
240→            c.stage, c.trainer_type, c.energy_type, c.suffix, c.retreat, c.effect,
241→            c.evolve_from, c.set_id, s.name as set_name
242→     FROM cards c
243→     LEFT JOIN sets s ON c.set_id = s.id
244→     WHERE c.image IS NOT NULL AND c.image != ''${filters}
245→     ORDER BY c.name ASC, c.id ASC
246→     LIMIT ? OFFSET ?`
247→  )
248→    .bind(...params, limit, offset)
249→    .all();
250→
251→  const cardIds = rows.results.map((r: any) => r.id as string);
252→
253→  if (cardIds.length === 0) {
254→    c.header("Cache-Control", "public, max-age=300, s-maxage=3600, stale-while-revalidate=86400");
255→    return c.json({ data: [], total, hasMore: false });
256→  }
257→
258→  // Batch-fetch related data for all cards in the page
259→  const ph = cardIds.map(() => "?").join(",");
260→  const [attacks, abilities, modifiers, types] = await Promise.all([
261→    db.prepare(`SELECT * FROM card_attacks WHERE card_id IN (${ph}) ORDER BY card_id, position`).bind(...cardIds).all(),
262→    db.prepare(`SELECT * FROM card_abilities WHERE card_id IN (${ph})`).bind(...cardIds).all(),
263→    db.prepare(`SELECT * FROM card_type_modifiers WHERE card_id IN (${ph})`).bind(...cardIds).all(),
264→    db.prepare(`SELECT * FROM card_types WHERE card_id IN (${ph})`).bind(...cardIds).all(),
265→  ]);
266→
267→  const attacksByCard = groupBy(attacks.results as any[], "card_id");
268→  const abilitiesByCard = groupBy(abilities.results as any[], "card_id");
269→  const modifiersByCard = groupBy(modifiers.results as any[], "card_id");
270→  const typesByCard = groupBy(types.results as any[], "card_id");
271→
272→  const parsed = rows.results.map((card: any) =>
273→    assembleCard(
274→      card,
275→      attacksByCard.get(card.id) ?? [],
276→      abilitiesByCard.get(card.id) ?? [],
277→      modifiersByCard.get(card.id) ?? [],
278→      typesByCard.get(card.id) ?? [],
279→    ),
280→  );
281→
282→  c.header("Cache-Control", "public, max-age=300, s-maxage=3600, stale-while-revalidate=86400");
283→
284→  return c.json({
285→    data: parsed,
286→    total,
287→    hasMore: offset + rows.results.length < total,
288→  });
289→});
290→
291→// ---------------------------------------------------------------------------
292→// GET /:id (detail)
293→// ---------------------------------------------------------------------------
294→
295→cardsRoute.get("/:id", async (c) => {
296→  const id = c.req.param("id");
297→  const db = c.env.DB;
298→
299→  const [card, attacks, abilities, modifiers, types] = await Promise.all([
300→    db.prepare(
301→      `SELECT c.*, s.name as set_name, s.logo as set_logo, s.symbol as set_symbol,
302→              s.release_date as set_release_date
303→       FROM cards c
304→       LEFT JOIN sets s ON c.set_id = s.id
305→       WHERE c.id = ?`
306→    )
307→      .bind(id)
308→      .first(),
309→    db.prepare("SELECT * FROM card_attacks WHERE card_id = ? ORDER BY position").bind(id).all(),
310→    db.prepare("SELECT * FROM card_abilities WHERE card_id = ?").bind(id).all(),
311→    db.prepare("SELECT * FROM card_type_modifiers WHERE card_id = ?").bind(id).all(),
312→    db.prepare("SELECT * FROM card_types WHERE card_id = ?").bind(id).all(),
313→  ]);
314→
315→  if (!card) {
316→    return c.json({ error: "Card not found" }, 404);
317→  }
318→
319→  const parsed = assembleCard(
320→    { ...card, dex_ids: safeJsonParse(card.dex_ids as string | null, []) },
321→    attacks.results as any[],
322→    abilities.results as any[],
323→    modifiers.results as any[],
324→    types.results as any[],
325→  );
326→
327→  c.header("Cache-Control", "public, max-age=300, s-maxage=3600, stale-while-revalidate=86400");
328→
329→  return c.json({ data: parsed });
330→});
331→
332→export { cardsRoute };
333→

