  1→import type {
  2→  CardDetail,
  3→  CardListResponse,
  4→  DeckSummary,
  5→  FilterOptions,
  6→  SimulatorRulesResponse,
  7→  SetListResponse,
  8→} from "./types";
  9→import type { SimulatorAction, SimulatorStore } from "@luminous/simulator-core";
 10→
 11→export const API_URL =
 12→  import.meta.env.VITE_API_URL ??
 13→  import.meta.env.PUBLIC_API_URL ??
 14→  "";
 15→
 16→export function imageUrl(key: string | null): string | null {
 17→  if (!key) return null;
 18→  return `${API_URL}/images/${key}`;
 19→}
 20→
 21→const MAX_CACHE_SIZE = 200;
 22→const cache = new Map<string, { data: CardListResponse; ts: number }>();
 23→const cardDetailCache = new Map<string, { data: CardDetail; ts: number }>();
 24→const CACHE_TTL = 5 * 60 * 1000; // 5 minutes
 25→
 26→function evictOldest(map: Map<string, { ts: number }>) {
 27→  if (map.size <= MAX_CACHE_SIZE) return;
 28→  let oldestKey: string | null = null;
 29→  let oldestTs = Infinity;
 30→  for (const [key, entry] of map) {
 31→    if (entry.ts < oldestTs) {
 32→      oldestTs = entry.ts;
 33→      oldestKey = key;
 34→    }
 35→  }
 36→  if (oldestKey) map.delete(oldestKey);
 37→}
 38→
 39→function isRecord(value: unknown): value is Record<string, unknown> {
 40→  return typeof value === "object" && value !== null;
 41→}
 42→
 43→function isCardListResponse(value: unknown): value is CardListResponse {
 44→  if (!isRecord(value)) return false;
 45→  return (
 46→    Array.isArray(value.data) &&
 47→    typeof value.total === "number" &&
 48→    typeof value.hasMore === "boolean"
 49→  );
 50→}
 51→
 52→function isCardDetail(value: unknown): value is CardDetail {
 53→  return (
 54→    isRecord(value) &&
 55→    typeof value.id === "string" &&
 56→    typeof value.local_id === "string" &&
 57→    typeof value.name === "string" &&
 58→    typeof value.category === "string" &&
 59→    typeof value.set_id === "string"
 60→  );
 61→}
 62→
 63→function isStringArray(value: unknown): value is string[] {
 64→  return Array.isArray(value) && value.every((item) => typeof item === "string");
 65→}
 66→
 67→function isNumberArray(value: unknown): value is number[] {
 68→  return Array.isArray(value) && value.every((item) => typeof item === "number");
 69→}
 70→
 71→function isFilterOptions(value: unknown): value is FilterOptions {
 72→  if (!isRecord(value) || !isRecord(value.hp)) return false;
 73→
 74→  return (
 75→    isStringArray(value.categories) &&
 76→    isStringArray(value.rarities) &&
 77→    isStringArray(value.stages) &&
 78→    isStringArray(value.trainer_types) &&
 79→    isStringArray(value.energy_types) &&
 80→    isStringArray(value.types) &&
 81→    isStringArray(value.weaknesses) &&
 82→    isStringArray(value.resistances) &&
 83→    isNumberArray(value.retreats) &&
 84→    typeof value.hp.min === "number" &&
 85→    typeof value.hp.max === "number" &&
 86→    isStringArray(value.regulation_marks)
 87→  );
 88→}
 89→
 90→function hasDataEnvelope<T>(
 91→  value: unknown,
 92→  guard: (input: unknown) => input is T,
 93→): value is { data: T } {
 94→  return isRecord(value) && guard(value.data);
 95→}
 96→
 97→function parseJson<T>(
 98→  value: unknown,
 99→  guard: (input: unknown) => input is T,
100→  message: string,
101→): T {
102→  if (!guard(value)) {
103→    throw new Error(message);
104→  }
105→
106→  return value;
107→}
