109→export async function fetchCards(params: {
110→  q?: string;
111→  category?: string;
112→  set?: string;
113→  limit?: number;
114→  offset?: number;
115→  rarity?: string;
116→  stage?: string;
117→  trainer_type?: string;
118→  energy_type?: string;
119→  retreat?: string;
120→  hp_min?: string;
121→  hp_max?: string;
122→  types?: string;
123→  weakness?: string;
124→  resistance?: string;
125→  legal_standard?: string;
126→  legal_expanded?: string;
127→}): Promise<CardListResponse> {
128→  const url = new URL("/api/cards", API_URL);
129→
130→  if (params.q) url.searchParams.set("q", params.q);
131→  if (params.category) url.searchParams.set("category", params.category);
132→  if (params.set) url.searchParams.set("set", params.set);
133→  if (params.limit != null) url.searchParams.set("limit", String(params.limit));
