242→function isAttackRule(value: unknown): value is SimulatorRulesResponse["attacks"][number] {
243→  return (
244→    isRecord(value) &&
245→    typeof value.index === "number" &&
246→    typeof value.name === "string" &&
247→    isRuleStatus(value)
248→  );
249→}
