 21→/** Reconstruct the original damage value (number | string) from damage_raw */
 22→function reconstructDamage(raw: string): string | number | undefined {
 23→  if (!raw) return undefined;
 24→  const num = parseInt(raw, 10);
 25→  if (!isNaN(num) && String(num) === raw) return num;
 26→  return raw;
 27→}
 28→
 29→/** Group an array of rows by a string key */
 30→function groupBy<T extends Record<string, unknown>>(rows: T[], key: keyof T): Map<string, T[]> {
 31→  const map = new Map<string, T[]>();
 32→  for (const row of rows) {
 33→    const k = String(row[key]);
 34→    const arr = map.get(k);
 35→    if (arr) arr.push(row);
 36→    else map.set(k, [row]);
 37→  }
 38→  return map;
 39→}
 40→
 41→/** Build attack objects matching original API shape */
 42→function assembleAttacks(rows: any[]): any[] {
 43→  return rows.map((r) => {
 44→    const attack: Record<string, unknown> = {
 45→      cost: safeJsonParse(r.cost, []),
 46→      name: r.name,
 47→    };
 48→    const damage = reconstructDamage(r.damage_raw);
 49→    if (damage !== undefined) attack.damage = damage;
 50→    if (r.effect != null) attack.effect = r.effect;
 51→    return attack;
 52→  });
 53→}
