  8→function safeJsonParse<T>(value: string | null | undefined, fallback: T): T {
  9→  if (!value || typeof value !== "string") return fallback;
 10→  try {
 11→    return JSON.parse(value) as T;
 12→  } catch {
 13→    return fallback;
 14→  }
 15→}
 16→
 17→function reconstructDamage(raw: string): string | number | undefined {
 18→  if (!raw) return undefined;
 19→  const num = parseInt(raw, 10);
 20→  if (!Number.isNaN(num) && String(num) === raw) return num;
 21→  return raw;
 22→}
 23→
 24→function assembleAttacks(rows: Array<Record<string, unknown>>): Array<Record<string, unknown>> {
 25→  return rows.map((row) => {
 26→    const attack: Record<string, unknown> = {
 27→      cost: safeJsonParse(row.cost as string | null | undefined, []),
 28→      name: row.name,
 29→    };
 30→    const damage = reconstructDamage(String(row.damage_raw ?? ""));
 31→    if (damage !== undefined) attack.damage = damage;
 32→    if (row.effect != null) attack.effect = row.effect;
 33→    return attack;
 34→  });
 35→}
 36→
 37→function assembleCard(
 38→  card: Record<string, unknown>,
 39→  attacks: Array<Record<string, unknown>>,
 40→  abilities: Array<Record<string, unknown>>,
 41→  modifiers: Array<Record<string, unknown>>,
 42→  types: Array<Record<string, unknown>>,
 43→) {
 44→  return {
 45→    ...card,
 46→    tera: Boolean(card.tera),
 47→    types: types.map((type) => type.type),
 48→    attacks: assembleAttacks(attacks),
 49→    abilities: abilities.map((ability) => ({ type: ability.type, name: ability.name, effect: ability.effect })),
 50→    weaknesses: modifiers
 51→      .filter((modifier) => modifier.kind === "weakness")
 52→      .map((modifier) => ({ type: modifier.type, value: modifier.value })),
 53→    resistances: modifiers
 54→      .filter((modifier) => modifier.kind === "resistance")
 55→      .map((modifier) => ({ type: modifier.type, value: modifier.value })),
 56→  };
 57→}
