 62→    db.prepare(
 63→      `SELECT c.id, c.local_id, c.name, c.image, c.category, c.rarity, c.hp,
 64→              c.stage, c.trainer_type, c.energy_type, c.suffix, c.tera, c.retreat, c.effect,
 65→              c.evolve_from, c.set_id, s.name as set_name
 66→       FROM cards c
 67→       LEFT JOIN sets s ON c.set_id = s.id
 68→       WHERE c.id = ?`
 69→    ).bind(id).first(),
