 86→async function searchCardByName(c: AppEnv["Bindings"] extends never ? never : any, query: string): Promise<CardSummary | null> {
 87→  const db = c.env.DB as D1Database;
 88→  const exact = await db.prepare(
 89→    `SELECT c.id
 90→     FROM cards c
 91→     WHERE lower(c.name) = lower(?)
 92→     ORDER BY c.id ASC
 93→     LIMIT 1`
 94→  ).bind(query.trim()).first<{ id: string }>();
 95→
 96→  if (exact?.id) {
 97→    return loadCardById(c, exact.id);
 98→  }
 99→
100→  const like = await db.prepare(
101→    `SELECT c.id
102→     FROM cards c
103→     WHERE c.name LIKE ?
104→     ORDER BY c.name ASC, c.id ASC
105→     LIMIT 1`
106→  ).bind(`%${query.trim()}%`).first<{ id: string }>();
107→
108→  if (!like?.id) return null;
109→  return loadCardById(c, like.id);
110→}
