148→function shuffle<T>(arr: T[]): T[] {
149→  const out = [...arr];
150→  for (let i = out.length - 1; i > 0; i -= 1) {
151→    const j = Math.floor(Math.random() * (i + 1));
152→    [out[i], out[j]] = [out[j], out[i]];
153→  }
154→  return out;
155→}
156→
157→function drawFromDeck<T>(deck: T[], count: number): T[] {
158→  const out: T[] = [];
159→  for (let i = 0; i < count && deck.length > 0; i += 1) {
160→    const card = deck.shift();
161→    if (card) out.push(card);
162→  }
163→  return out;
164→}
165→
166→function hasBasicInHand(hand: CardInstance[]): boolean {
167→  return hand.some((card) => card.card.category === "Pokemon" && card.card.stage === "Basic");
168→}
169→
170→function autoMulliganUntilBasic(player: Pick<PlayerBoard, "hand" | "deck" | "mulligans">) {
171→  if (!hasBasicInHand([...player.hand, ...player.deck])) return false;
172→  while (!hasBasicInHand(player.hand)) {
173→    player.mulligans += 1;
174→    player.deck = shuffle([...player.deck, ...player.hand]);
175→    player.hand = drawFromDeck(player.deck, 7);
176→  }
177→  return true;
178→}
