331→simulatorRoute.post("/new-game", async (c) => {
332→  const body = await c.req.json().catch(() => null);
333→  if (!isNewGameBody(body)) {
334→    return c.json({ error: "Invalid simulator setup payload." }, 400);
335→  }
336→
337→  let uidCounter = 0;
338→  const nextUid = () => {
339→    uidCounter += 1;
340→    return `sim-${uidCounter}`;
341→  };
342→
343→  const [deck1Result, deck2Result] = await Promise.all([
344→    buildDeck(c, body.deck1, "Deck 1", nextUid),
345→    buildDeck(c, body.deck2, "Deck 2", nextUid),
346→  ]);
347→
348→  const setupErrors = [...deck1Result.errors, ...deck2Result.errors];
349→  if (!deck1Result.deck || !deck2Result.deck) {
350→    return c.json({ error: "Unable to build decks.", details: setupErrors }, 400);
351→  }
352→
353→  const p1 = createEmptyPlayer();
354→  const p2 = createEmptyPlayer();
355→  p1.deck = deck1Result.deck;
356→  p2.deck = deck2Result.deck;
357→  p1.hand = drawFromDeck(p1.deck, 7);
358→  p2.hand = drawFromDeck(p2.deck, 7);
359→
360→  if (!autoMulliganUntilBasic(p1)) {
361→    return c.json({ error: "Deck 1 has no Basic Pokemon and cannot complete setup." }, 400);
362→  }
363→  if (!autoMulliganUntilBasic(p2)) {
364→    return c.json({ error: "Deck 2 has no Basic Pokemon and cannot complete setup." }, 400);
365→  }
366→
367→  const shared = Math.min(p1.mulligans, p2.mulligans);
368→  const bonus1 = Math.max(0, p2.mulligans - shared);
369→  const bonus2 = Math.max(0, p1.mulligans - shared);
370→  p1.hand.push(...drawFromDeck(p1.deck, bonus1));
371→  p2.hand.push(...drawFromDeck(p2.deck, bonus2));
372→
373→  const coinFlipResult = Math.random() < 0.5 ? "Heads" : "Tails";
374→  const firstPlayer = coinFlipResult === "Heads" ? 0 : 1;
375→
376→  const store: SimulatorStore = {
377→    phase: "setup",
378→    winner: null,
379→    coinFlipResult,
380→    deckInput1: body.deck1,
381→    deckInput2: body.deck2,
382→    loading: false,
383→    firstPlayer,
384→    currentTurn: firstPlayer,
385→    turnNumber: 0,
386→    turnDrawDone: false,
387→    selectedHandUid: [null, null],
388→    selectedPrizeUid: [null, null],
389→    revealedPrizeUids: [[], []],
390→    nameQueryCache: {},
391→    logs: [
392→      `Mulligans -> P1: ${p1.mulligans}, P2: ${p2.mulligans}.`,
393→      `Coin flip: ${coinFlipResult}. P${firstPlayer + 1} goes first.`,
394→    ],
395→    players: [p1, p2],
396→    stadium: null,
397→    pendingHandSelection: null,
398→    pendingDeckSearch: null,
399→    pendingDiscardSelection: null,
400→    pendingOpponentSwitch: null,
401→    pendingSelfSwitch: null,
402→    pendingRareCandy: null,
403→    pendingEvolveFromDeck: null,
404→    pendingBenchDiscard: null,
405→    stadiumUsedThisTurn: [false, false],
406→    gameStarted: true,
407→  };
408→
409→  return c.json({ data: store });
410→});
